import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css'; // तुमची CSS फाईल (असल्यास)
import App from './App';

// १. प्रथम 'root' element अस्तित्वात आहे का ते तपासा
const rootElement = document.getElementById('root');

if (!rootElement) {
    // जर root सापडला नाही, तर कंसोलमध्ये एरर दाखवा (Debugging साठी सोपे पडेल)
    console.error("Target container 'root' is missing from index.html");
} else {
    // २. जर root सापडला, तरच React Render करा
    const root = ReactDOM.createRoot(rootElement);
    root.render(
        <React.StrictMode>
            <App />
        </React.StrictMode>
    );
}
